before(() => {
        app = cluster('apps/egg-ready', {
          workers: 2,
          opt: { execArgv: [ `--${debugProtocol}` ] },
        });
        // app.debug();
        setTimeout(() => {
          app.proc.on('message', (msg: any) => {
            if (msg.to === 'parent' && msg.action === 'debug') {
              if (msg.from === 'agent') {
                result.agent = msg.data;
              } else {
                result.app.push(msg.data);
              }
            }
          });
        }, 1);
        return app.ready();
      })

