  orm.em.create(User, {
    id: 'emp-match',
    name: 'Matched Employee',
    belongsTo: matchingCompany,
    primaryCompany: matchingCompany,
  });
  orm.em.create(User, {
    id: 'emp-other',
    name: 'Other Employee',
    belongsTo: otherCompany,
    primaryCompany: otherCompany,
  });
  orm.em.create(Company, { id: 'company-1', title: 'C1', owner });
  await orm.em.flush();
  orm.em.clear();
})

