beforeEach(async function () {
        callOrder = [];

        const firstPlugin: HardhatPlugin = {
          id: "test-on-build-first-plugin",
          hookHandlers: {
            solidity: async () => ({
              default: async () => {
                const handlers: Partial<SolidityHooks> = {
                  onBuild: async (
                    context: HookContext,
                    rootFilePaths: string[],
